export const getDownloadReportUrl = (analysisId: number,) => {




  return `/api/reports/${analysisId}`
}

/**
 * @summary Get report data for an analysis
 */
export const downloadReport = async (analysisId: number, options?: RequestInit): Promise<Report> => {

  return customFetch<Report>(getDownloadReportUrl(analysisId),
  {
    ...options,
    method: 'GET'


  }
);}





export const getDownloadReportQueryKey = (analysisId: number,) => {
    return [
    `/api/reports/${analysisId}`
    ] as const;
    }


export const getDownloadReportQueryOptions = <TData = Awaited<ReturnType<typeof downloadReport>>, TError = ErrorType<unknown>>(analysisId: number, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof downloadReport>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getDownloadReportQueryKey(analysisId);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof downloadReport>>> = ({ signal }) => downloadReport(analysisId, { signal, ...requestOptions });





   return  { queryKey, queryFn, enabled: !!(analysisId), ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof downloadReport>>, TError, TData> & { queryKey: QueryKey }
}

export type DownloadReportQueryResult = NonNullable<Awaited<ReturnType<typeof downloadReport>>>
export type DownloadReportQueryError = ErrorType<unknown>


/**
 * @summary Get report data for an analysis
 */

export function useDownloadReport<TData = Awaited<ReturnType<typeof downloadReport>>, TError = ErrorType<unknown>>(
 analysisId: number, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof downloadReport>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getDownloadReportQueryOptions(analysisId,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







